  ('elementary-0c700c30-moex-00001', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '目前各國衡量一國的經濟成長常會使用國民所得的數據來顯示，但國民所得的數據只是整體與平均經濟 狀況表象，下列何種曲線可以呈現國民所得分配不均程度？', '["恩格爾曲線", "菲利浦曲線", "勞倫斯曲線", "生產可能曲線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00002', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '某國生產兩種產品（X與Y，分別表示為水平軸與垂直軸），其凹向原點的生產可能曲線上，由左上往右 下依序為A、B、C三個點，下列敘述何者正確？', '["就生產效率的大小而言，A＞B＞C", "多生產一單位X的機會成本為A＞B＞C", "就生產效率的大小而言，A＝B＝C", "多生產一單位Y的機會成本為A＝B＝C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00003', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）旨在促進泛太平洋國家間的貿易自由化。依其宗旨判斷，參與此種 經濟合作組織的國家，會產生下列何種現象？', '["勞動要素可自由流動", "各國間實施關稅保護", "共同發行統一的貨幣", "市場上商品種類增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00004', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '對社會而言，下列那一種財貨或服務的機會成本最低？', '["政府提供的免費服務", "不具相對稀少性的物品", "準備拿來當作肥料的雞糞", "無法提升消費者效用的物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00005', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '市場上的生產者與消費者會隨著產品價格的上漲或下跌，不斷地調整其生產或消費行為，最後會達到市場 均衡。下列針對此市場均衡的相關敘述，何者正確？', '["無謂損失等於零", "生產者剩餘達到最小值", "社會總剩餘等於消費者剩餘", "社會福利等於社會總效益加社會總成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00006', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '假設政府發出公告：「近來國內經濟發展穩定，經政府核定列冊之低收入戶及中低收入戶，政府會加發生 活補助，低收入戶每人每月發給750元，中低收入戶每人每月發給500元」。前述政策內容，最符合下列 何項理論的內涵？', '["符合多數人福祉的效益主義觀點", "照顧弱勢者權益的社會平等觀點", "追求群體共同利益的社群主義觀點", "透過私利實現公益的自由主義觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00007', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '有學者研究指出臺灣高等教育「反向重分配」的事實：社會地位越高的家庭，相對於較低的家庭，其子女反 而能得到較多的政府教育資源。從經濟資本與文化資本兩個概念來觀察，下列敘述何者最能符合題文的描述？', '["父母職業聲望對子女社會地位影響力擴大", "親子間社會地位的世代流動距離得以擴大", "父母的成就動機對子女社會地位流動的影響得以擴大", "父母的教育程度高低對子女社會地位流動的影響變小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
